class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def count_complete_tree_nodes(root: TreeNode) -> int:
    if not root:
        return 0

    def get_leftmost_height(node):
        height = 0
        while node:
            node = node.left
            height += 1
        return height

    h = get_leftmost_height(root)

    if get_leftmost_height(root.right) == h - 1:
        return (1 << (h - 1)) + count_complete_tree_nodes(root.right)
    else:
        return count_complete_tree_nodes(root.left) + (1 << (h - 2))
